export const submitIdwlResponseCompanionOscillationFrequencyMin = 0;
export const submitIdwlResponseCompanionOscillationFrequencyMax = 4;

export const submitIdwlResponseCompanionControlMax = 5;

export const SubmitIdwlResponse = zod.object({
  id: zod.number(),
  lossOriented: zod.number().describe("Sum of items 1-11 (11-44)"),
  restorationOriented: zod.number().describe("Sum of items 12-22 (11-44)"),
  balance: zod
    .number()
    .describe("restorationOriented - lossOriented (-33..33)"),
  companion: zod
    .object({
      awarenessLoss: zod
        .number()
        .min(1)
        .max(submitIdwlResponseCompanionAwarenessLossMax)
        .describe("C1 attention to grief\/emotions"),
      awarenessRestoration: zod
        .number()
        .min(1)
        .max(submitIdwlResponseCompanionAwarenessRestorationMax)
        .describe("C2 attention to new responsibilities"),
      oscillationFrequency: zod
        .number()
        .min(submitIdwlResponseCompanionOscillationFrequencyMin)
        .max(submitIdwlResponseCompanionOscillationFrequencyMax)
        .describe(
          "C3 how often gone back and forth (0=only one issue .. 4=several times each day)",
        ),
      control: zod
        .number()
        .min(1)
        .max(submitIdwlResponseCompanionControlMax)
        .describe("C4 control over going back and forth"),
    })
    .describe("IDWL companion items on the Dual Process oscillation."),
  responses: zod.array(zod.number()),
  completedAt: zod.coerce.date(),
});

